// ══════════════════════════════════════════════════════════════════════
// v128: PageContainer — compact desktop layout chuẩn (960px)
// Chuẩn max-width: 960px cho page thường, 640px cho form narrow
// ══════════════════════════════════════════════════════════════════════
const LAYOUT = {
  pageMax:   960,   // Tối đa cho content chính
  formMax:   640,   // Form nhập liệu
  narrowMax: 480,   // Input code, search, v.v.
  tightMax:  320,   // Button group, toggle
} as const

function PageContainer({ children, mobile, width = 'page', noPad }: {
  children: any,
  mobile?: boolean,
  width?: 'page' | 'form' | 'narrow' | 'full',
  noPad?: boolean,
}) {
  const maxW = mobile
    ? '100%'
    : width === 'full'   ? 'none'
    : width === 'form'   ? LAYOUT.formMax
    : width === 'narrow' ? LAYOUT.narrowMax
    : LAYOUT.pageMax
  return (
    <div style={{
      maxWidth: maxW,
      margin: '0 auto',
      width: '100%',
      padding: noPad ? 0 : (mobile ? '0 16px 80px' : '0 24px 24px'),
      boxSizing: 'border-box',
    }}>
      {children}
    </div>
  )
}

// FitButton — button compact, fit-content, không full width
function FitButton({ children, onClick, variant = 'primary', disabled, style, size = 'md' }: any) {
  const variants: any = {
    primary:   { bg: T.blue,  color: '#fff',    border: T.blue },
    success:   { bg: T.green, color: '#fff',    border: T.green },
    danger:    { bg: '#fff',  color: T.red,     border: T.red },
    ghost:     { bg: 'transparent', color: T.med, border: T.border },
    gold:      { bg: T.gold,  color: '#fff',    border: T.gold },
  }
  const v = variants[variant] || variants.primary
  const sizes: any = {
    sm: { padX: 10, padY: 6, font: 11 },
    md: { padX: 14, padY: 8, font: 12 },
    lg: { padX: 18, padY: 10, font: 13 },
  }
  const s = sizes[size] || sizes.md
  return (
    <button onClick={onClick} disabled={disabled}
      style={{
        padding: `${s.padY}px ${s.padX}px`,
        borderRadius: 8,
        cursor: disabled ? 'default' : 'pointer',
        background: disabled ? T.border : v.bg,
        color: disabled ? T.light : v.color,
        border: `1.5px solid ${disabled ? T.border : v.border}`,
        fontSize: s.font,
        fontWeight: 600,
        fontFamily: 'inherit',
        whiteSpace: 'nowrap',
        ...(style || {}),
      }}>
      {children}
    </button>
  )
}

// TwoColResponsive — 2 cột desktop, 1 cột mobile
function TwoColResponsive({ left, right, mobile, leftRatio = 1, rightRatio = 1, gap = 16 }: any) {
  if (mobile) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap }}>
        <div>{left}</div>
        <div>{right}</div>
      </div>
    )
  }
  return (
    <div style={{ display: 'grid', gridTemplateColumns: `${leftRatio}fr ${rightRatio}fr`, gap }}>
      <div>{left}</div>
      <div>{right}</div>
    </div>
  )
}

// ── KV SYNC BADGE — hiển thị trạng thái sync KiotViet ─────────────────
// Data từ `kv_sync_status.last_success_at` (server cron ghi mỗi 30s)
// 🟢 < 1 phút — fresh | 🟡 1-3 phút — stale | 🔴 > 3 phút — sync failing
function KVSyncBadge({ serverSyncAt, fetching, paused }: { serverSyncAt: Date|null, fetching?: boolean, paused?: boolean }) {
  // Tick tự động để auto-update "X giây trước" mỗi 10s
  const [, forceTick] = useState(0)
  useEffect(() => {
    const i = setInterval(() => forceTick(t => t + 1), 10000)
    return () => clearInterval(i)
  }, [])

  if (paused) {
    return <span style={{ fontSize: 10, color: T.amber, fontWeight: 600 }}>⏸ Pause (đang mở đơn)</span>
  }
  if (fetching) {
    return <span style={{ fontSize: 10, color: T.blue, fontWeight: 600 }}>🔄 Đang cập nhật...</span>
  }
  if (!serverSyncAt) {
    return <span style={{ fontSize: 10, color: T.med }}>⏳ Chưa có data sync</span>
  }

  const elapsedSec = Math.floor((Date.now() - serverSyncAt.getTime()) / 1000)
  let color = T.green, icon = '🟢', label = ''
  if (elapsedSec < 60) {
    label = `Cập nhật ${elapsedSec}s trước`
  } else if (elapsedSec < 180) {
    color = T.amber; icon = '🟡'
    label = `Cập nhật ${Math.floor(elapsedSec / 60)} phút trước`
  } else {
    color = T.red; icon = '🔴'
    label = `⚠️ Data cũ ${Math.floor(elapsedSec / 60)} phút — cron sync lỗi?`
  }

  return (
    <span style={{
      fontSize: 10, color, fontWeight: 600,
      padding: '3px 8px', borderRadius: 12,
      background: color + '15', border: `1px solid ${color}40`,
      whiteSpace: 'nowrap',
    }} title={`Server sync lúc ${serverSyncAt.toLocaleTimeString('vi-VN')}`}>
      {icon} {label}
    </span>
  )
}

// ── CONFIRM DELETE MODAL — Yêu cầu gõ "XÓA" để xác nhận destructive actions ──
function ConfirmDeleteModal({
  title = 'Xóa dữ liệu',
  message,
  detail,
  confirmWord = 'XÓA',
  onConfirm,
  onCancel,
}: {
  title?: string, message: string, detail?: string,
  confirmWord?: string,
  onConfirm: () => void, onCancel: () => void
}) {
  const [typed, setTyped] = useState('')
  const [deleting, setDeleting] = useState(false)
  const match = typed.trim().toUpperCase() === confirmWord.toUpperCase()

  const handleConfirm = async () => {
    if (!match || deleting) return
    setDeleting(true)
    try {
      await onConfirm()
    } finally {
      setDeleting(false)
    }
  }

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:460, width:'100%',
        border:`2px solid ${T.red}`, overflow:'hidden' }}>
        <div style={{ padding:'14px 20px', background:T.redBg, borderBottom:`1px solid ${T.red}` }}>
          <div style={{ fontSize:15, fontWeight:700, color:T.red, display:'flex', alignItems:'center', gap:8 }}>
            ⚠️ {title}
          </div>
        </div>
        <div style={{ padding:20 }}>
          <div style={{ fontSize:13, color:T.dark, marginBottom:10, lineHeight:1.5 }}>
            {message}
          </div>
          {detail && (
            <div style={{ fontSize:12, color:T.med, padding:'8px 10px', background:T.bg,
              borderRadius:6, marginBottom:14, border:`1px solid ${T.border}`, lineHeight:1.5,
              whiteSpace:'pre-wrap' }}>
              {detail}
            </div>
          )}
          <div style={{ fontSize:12, color:T.red, fontWeight:600, marginBottom:6 }}>
            ⚠️ Hành động này KHÔNG thể hoàn tác. Mọi thao tác xóa sẽ được ghi vào nhật ký.
          </div>
          <label style={{ fontSize:12, color:T.med, display:'block', marginBottom:6 }}>
            Để xác nhận, gõ <b style={{ color:T.red, fontFamily:'monospace' }}>{confirmWord}</b> vào ô dưới:
          </label>
          <input value={typed} onChange={e => setTyped(e.target.value)} autoFocus
            placeholder={confirmWord}
            style={{ width:'100%', padding:'10px 13px', border:`2px solid ${match?T.green:T.border}`, borderRadius:6,
              fontSize:14, fontFamily:'monospace', color:T.dark, background:'#fff', outline:'none',
              boxSizing:'border-box' as any, marginBottom:16, letterSpacing:2 }}
            onKeyDown={e => e.key === 'Enter' && match && handleConfirm()}/>
          <div style={{ display:'flex', gap:10 }}>
            <button onClick={onCancel}
              style={{ flex:1, padding:'9px', borderRadius:6, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
              Hủy
            </button>
            <button onClick={handleConfirm} disabled={!match || deleting}
              style={{ flex:1, padding:'9px', borderRadius:6, border:'none',
                background: match ? T.red : T.border,
                color: match ? '#fff' : T.light,
                cursor: match && !deleting ? 'pointer' : 'not-allowed',
                fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
              {deleting ? '⏳ Đang xóa...' : '🗑️ Xóa'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ── IN-APP ALERT BANNER ──────────────────────────
const AlertBanner = ({ user, checklist, leaveRequests, otRequests, allUsers }: any) => {
  const perm = getPerm(user)
  const dids = allUsers.filter((u: any) => u.dept_id === user.dept_id).map((u: any) => u.id)
  const overdueItems = checklist.filter((c: any) => c.assignee_id === user.id && isOverdue(c))
  const pendingLeave = leaveRequests.filter((r: any) => {
    if (r.status !== 'pending') return false
    if (perm.viewAllDashboard) return true
    if (perm.approveLeave) return dids.includes(r.user_id) && !['pending_admin','approved','rejected'].includes(r.status)
    return false
  })
  const pendingOT = (otRequests||[]).filter((r: any) => {
    if (r.status !== 'pending') return false
    if (perm.viewAllDashboard) return true
    if (perm.approveOT) return dids.includes(r.user_id)
    return false
  })
  const alerts = [
    ...overdueItems.map((c: any) => ({ msg:`⚠️ Trễ deadline: ${c.title}`, color:T.red, bg:T.redBg })),
    ...pendingLeave.map((r: any) => {
      const u = allUsers.find((u: any) => u.id === r.user_id)
      return { msg:`🏖️ ${u?.name} xin nghỉ ${r.days} ngày — chờ duyệt`, color:T.amber, bg:T.amberBg }
    }),
    ...pendingOT.map((r: any) => {
      const u = allUsers.find((u: any) => u.id === r.user_id)
      return { msg:`⏰ ${u?.name} đăng ký OT ${fmtDate(r.date)} — chờ duyệt`, color:T.blue, bg:T.blueBg }
    }),
  ]
  if (alerts.length === 0) return null
  return (
    <div style={{ margin:'0 0 14px', display:'flex', flexDirection:'column', gap:6 }}>
      {alerts.slice(0,3).map((a, i) => (
        <div key={i} style={{ padding:'8px 14px', borderRadius:8, fontSize:12, fontWeight:500,
          color:a.color, background:a.bg }}>{a.msg}</div>
      ))}
      {alerts.length > 3 && <div style={{ fontSize:11, color:T.light }}>+{alerts.length-3} thông báo khác...</div>}
    </div>
  )
}

