// ══════════════════════════════════════════════════════════════════════
// ══ PICKING MODULE v2 — Nhặt Hàng (redesign desktop-friendly) ════════
// ══════════════════════════════════════════════════════════════════════

// Shared: compress image (dùng cho cả Picking + Packing)
async function compressImageV2(file: File, maxW = 1920, quality = 0.82): Promise<Blob> {
  return new Promise((resolve, reject) => {
    const img = new Image()
    const reader = new FileReader()
    reader.onload = () => {
      img.onload = () => {
        let { width, height } = img
        if (width > maxW) {
          height = Math.round((height * maxW) / width)
          width = maxW
        }
        const canvas = document.createElement('canvas')
        canvas.width = width
        canvas.height = height
        const ctx = canvas.getContext('2d')
        if (!ctx) { reject(new Error('canvas ctx')); return }
        ctx.drawImage(img, 0, 0, width, height)
        canvas.toBlob(blob => blob ? resolve(blob) : reject(new Error('compress fail')), 'image/jpeg', quality)
      }
      img.onerror = () => reject(new Error('img load fail'))
      img.src = reader.result as string
    }
    reader.onerror = () => reject(new Error('read fail'))
    reader.readAsDataURL(file)
  })
}

// v123: Dual-version compress — 1 ảnh gốc 2048px + 1 ảnh AI 1024px
// Ảnh gốc: dùng hiển thị + audit đơn nhầm
// Ảnh AI: chỉ gửi OpenAI (tiết kiệm ~90% tokens)
async function compressImageDual(file: File): Promise<{ fullBlob: Blob; aiBlob: Blob }> {
  // Đọc ảnh 1 lần, resize 2 phiên bản
  return new Promise((resolve, reject) => {
    const img = new Image()
    const reader = new FileReader()
    reader.onload = () => {
      img.onload = async () => {
        const makeBlob = (maxW: number, quality: number): Promise<Blob> => {
          return new Promise((res, rej) => {
            let { width, height } = img
            if (width > maxW) {
              height = Math.round((height * maxW) / width)
              width = maxW
            }
            const canvas = document.createElement('canvas')
            canvas.width = width
            canvas.height = height
            const ctx = canvas.getContext('2d')
            if (!ctx) { rej(new Error('canvas ctx')); return }
            ctx.drawImage(img, 0, 0, width, height)
            canvas.toBlob(b => b ? res(b) : rej(new Error('blob fail')), 'image/jpeg', quality)
          })
        }
        try {
          const [fullBlob, aiBlob] = await Promise.all([
            makeBlob(2048, 0.85),  // Ảnh gốc: 2048px, quality 0.85 → ~500KB, đủ rõ để audit
            makeBlob(1024, 0.78),  // Ảnh AI:  1024px, quality 0.78 → ~150KB, đủ rõ cho OpenAI
          ])
          resolve({ fullBlob, aiBlob })
        } catch(e) { reject(e) }
      }
      img.onerror = () => reject(new Error('img load fail'))
      img.src = reader.result as string
    }
    reader.onerror = () => reject(new Error('read fail'))
    reader.readAsDataURL(file)
  })
}

// v123: Upload cả 2 phiên bản lên Supabase Storage → trả về { url, ai_url }
async function uploadPhotoDual(
  file: File,
  bucket: string,
  pathPrefix: string,
  userId: string,
): Promise<{ url: string; ai_url: string } | null> {
  try {
    const { fullBlob, aiBlob } = await compressImageDual(file)
    const ts = Date.now()
    const safeUserId = (userId || 'unknown')
      .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
      .replace(/đ/g, 'd').replace(/Đ/g, 'D').replace(/[^a-zA-Z0-9_-]/g, '_')
    const baseName = `${safeUserId}_${ts}`

    const fullPath = `${pathPrefix}/${baseName}.jpg`
    const aiPath   = `${pathPrefix}/${baseName}_ai.jpg`

    // Upload song song cho nhanh
    const [fullRes, aiRes] = await Promise.all([
      db.storage.from(bucket).upload(fullPath, fullBlob, {
        contentType: 'image/jpeg', upsert: false,
      }),
      db.storage.from(bucket).upload(aiPath, aiBlob, {
        contentType: 'image/jpeg', upsert: false,
      }),
    ])
    if (fullRes.error) { toast.error('Upload lỗi: ' + fullRes.error.message); return null }
    if (aiRes.error) { console.warn('AI photo upload fail:', aiRes.error.message) }

    const { data: fullUrl } = db.storage.from(bucket).getPublicUrl(fullRes.data!.path)
    const { data: aiUrl } = aiRes.data
      ? db.storage.from(bucket).getPublicUrl(aiRes.data.path)
      : { data: { publicUrl: fullUrl.publicUrl } }  // fallback: nếu ai upload fail → dùng full

    return {
      url:    fullUrl.publicUrl,
      ai_url: aiUrl.publicUrl,
    }
  } catch(e: any) {
    toast.error('' + e.message)
    return null
  }
}

function photoCountRangeV2(totalItems: number) {
  // Min luôn là 1 theo yêu cầu của anh. max giữ để hạn chế dung lượng.
  // Suggest: gợi ý số ảnh lý tưởng (không bắt buộc, chỉ để popup nhắc)
  const min = 1
  const max = Math.min(10, Math.max(3, Math.ceil(totalItems / 10)))
  const suggest = Math.max(1, Math.ceil(totalItems / 10))  // 10 SP = 1 ảnh gợi ý
  return { min, max, suggest }
}

function PickingModule({ user, allUsers, mobile, products }: any) {
  const perm      = getPerm(user)
  const canPick   = perm.pickOrders || perm.viewAllDashboard
  const isAdmin   = perm.viewAllDashboard
  const p = mobile ? '16px' : '24px'

  // pickingProducts: fresh data cho các SP có trong đơn picking (fetch realtime theo codes)
  // Không đè root products → không ảnh hưởng các module khác
  const [pickingProducts, setPickingProducts] = useState<any[]>([])

  // Map product code → {stock, name, ordered_qty, ...}
  // Priority: pickingProducts (fresh) > root products (fallback)
  const productMap = useMemo(() => {
    const m = new Map<string, any>()
    ;(products || []).forEach((p: any) => m.set(p.code, p))
    ;(pickingProducts || []).forEach((p: any) => m.set(p.code, p))
    return m
  }, [products, pickingProducts])

  const [orders, setOrders]     = useState<any[]>([])
  const [loading, setLoading]   = useState(true)
  const [syncing, setSyncing]   = useState(false)
  const [lastSync, setLastSync] = useState<Date|null>(null)
  const [serverSyncAt, setServerSyncAt] = useState<Date|null>(null)  // server cron sync lần cuối
  const [selectedCode, setSelectedCode] = useState<string|null>(null)
  const [searchQ, setSearchQ] = useState('')
  const [tab, setTab] = useState<'todo'|'done_today'>('todo')
  // Cutoff date: chỉ hiển thị đơn từ ngày này trở đi (null = không filter)
  const [cutoffDate, setCutoffDate] = useState<string|null>(null)
  const [showCutoffModal, setShowCutoffModal] = useState(false)

  const fetchCutoff = async () => {
    const { data } = await db.from('settings')
      .select('picking_start_date').eq('id','main').maybeSingle()
    setCutoffDate(data?.picking_start_date || null)
  }
  useEffect(() => { fetchCutoff() }, [])

  const fetchData = async (quiet=false) => {
    if (!quiet) setSyncing(true)
    // Query 1: ALL orders đang picking
    const { data: pickingData } = await db.from('packing_workflow').select('*')
      .eq('status', 'picking')
      .order('purchase_date', { ascending: false })
    // Query 2: orders đã nhặt trong 3 ngày gần nhất
    const threeDaysAgo = new Date(Date.now() - 3*86400000).toISOString()
    const { data: donePickData } = await db.from('packing_workflow').select('*')
      .in('status', ['packing','done'])
      .gte('picked_at', threeDaysAgo)
      .order('picked_at', { ascending: false })
      .limit(500)
    // Query 3: server cron sync status
    const { data: syncStatus } = await db.from('kv_sync_status')
      .select('last_success_at').eq('id', 'picking').maybeSingle()
    // Query 4: scan các SP CODE có trong đơn picking + done_today
    // Fetch chỉ các SP đó từ products (thay vì load toàn bộ 2700+ SP)
    // → Nhanh hơn rất nhiều, chính xác realtime cho stock + ordered_qty
    const allCodes = new Set<string>()
    ;(pickingData || []).forEach((o: any) => (o.items || []).forEach((it: any) => {
      if (it.code) allCodes.add(it.code)
    }))
    ;(donePickData || []).forEach((o: any) => (o.items || []).forEach((it: any) => {
      if (it.code) allCodes.add(it.code)
    }))

    if (allCodes.size > 0) {
      const codes = Array.from(allCodes)
      const fetchedProducts: any[] = []
      // Chunk 500 codes/query để tránh URL quá dài (PostgREST limit ~8KB)
      for (let i = 0; i < codes.length; i += 500) {
        const chunk = codes.slice(i, i + 500)
        const { data } = await db.from('products').select('*').in('code', chunk)
        if (data) fetchedProducts.push(...data)
      }
      setPickingProducts(fetchedProducts)
    }

    setOrders([...(pickingData||[]), ...(donePickData||[])])
    setLastSync(new Date())
    if (syncStatus?.last_success_at) setServerSyncAt(new Date(syncStatus.last_success_at))
    if (!quiet) setSyncing(false)
    setLoading(false)
  }

  // Nút "Sync ngay" - gọi Edge Function trực tiếp để bypass cron (khi NV cần data ngay)
  const syncKV = async () => {
    setSyncing(true)
    try {
      const res = await fetch(`${SUPABASE_URL}/functions/v1/kiotviet-picking`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${SUPABASE_ANON}` }
      })
      const json = await res.json()
      if (json.error) toast.error('Sync lỗi: ' + json.error)
      // Đợi 1s để Edge Function ghi DB xong rồi mới fetch
      await new Promise(r => setTimeout(r, 1000))
      await fetchData(true)
    } catch(e: any) {
      toast.error('Sync lỗi: ' + e.message)
    }
    setSyncing(false)
  }

  useEffect(() => {
    fetchData()
  }, [])

  // Auto-refresh DB mỗi 15s (nhanh hơn cron 30s → NV thấy data ngay khi cron xong)
  // PAUSE khi user đang mở đơn (tránh disrupt công việc)
  useEffect(() => {
    if (selectedCode) return
    const interval = setInterval(() => {
      fetchData(true)  // Chỉ đọc DB, KHÔNG gọi KV — cron server đã lo phần sync
    }, 15000)
    return () => clearInterval(interval)
  }, [selectedCode])

  // Khi user bật tab lại (sau khi rời app) → fetch DB ngay để thấy data mới nhất
  useEffect(() => {
    const handleVisibility = () => {
      if (document.visibilityState === 'visible' && !selectedCode) {
        fetchData(true)
      }
    }
    document.addEventListener('visibilitychange', handleVisibility)
    return () => document.removeEventListener('visibilitychange', handleVisibility)
  }, [selectedCode])

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()
  const filterByQ = (list: any[]) => {
    const q = norm(searchQ)
    if (!q) return list
    return list.filter((o: any) => norm(`${o.order_code} ${o.customer_name} ${o.sold_by_name}`).includes(q))
  }

  // Cutoff filter: ẩn đơn có purchase_date < cutoff (nếu có set)
  const cutoffFilter = (o: any) => {
    if (!cutoffDate) return true
    if (!o.purchase_date) return true
    return new Date(o.purchase_date) >= new Date(cutoffDate + 'T00:00:00')
  }

  // Tab 'todo': đơn status='picking' (chờ nhặt)
  const todoOrders = filterByQ(orders.filter((o: any) => o.status === 'picking' && cutoffFilter(o))
    .sort((a: any, b: any) => new Date(a.purchase_date).getTime() - new Date(b.purchase_date).getTime()))

  // Tab 'done_today': đơn đã nhặt xong hôm nay (picked_at = today, status='packing' hoặc 'done')
  const todayStart = new Date()
  todayStart.setHours(0,0,0,0)
  const doneTodayOrders = filterByQ(orders.filter((o: any) =>
    o.picked_at && new Date(o.picked_at) >= todayStart && cutoffFilter(o)
  ).sort((a: any, b: any) => new Date(b.picked_at).getTime() - new Date(a.picked_at).getTime()))

  const displayOrders = tab === 'todo' ? todoOrders : doneTodayOrders

  // Tổng số lượng mỗi SP trong TẤT CẢ đơn status='picking' (để cảnh báo khi SP được đặt nhiều)
  // Trả về Map: { code → { totalQty, orderCount } }
  const totalOrderedByCode = useMemo(() => {
    const m = new Map<string, { totalQty: number, orderCount: number }>()
    orders.filter((o: any) => o.status === 'picking').forEach((o: any) => {
      (o.items || []).forEach((it: any) => {
        const cur = m.get(it.code) || { totalQty: 0, orderCount: 0 }
        cur.totalQty += (it.qty || 0)
        cur.orderCount += 1
        m.set(it.code, cur)
      })
    })
    return m
  }, [orders])

  // Update item picked qty
  const updatePickedQty = async (orderCode: string, itemCode: string, newQty: number) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const newItems = (ord.items || []).map((it: any) => {
      if (it.code === itemCode) {
        const clamped = Math.max(0, Math.min(newQty, it.qty))
        return { ...it, picked_qty: clamped, picked_at: clamped>0 ? new Date().toISOString() : null }
      }
      return it
    })
    const upd: any = {
      items: newItems,
      picking_started_at: ord.picking_started_at || new Date().toISOString(),
      updated_at: new Date().toISOString(),
    }
    // Ghi nhận NV đầu tiên tác động vào đơn là người nhặt
    if (!ord.assigned_to) upd.assigned_to = user.id
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  // Nhặt đủ toàn bộ: set picked_qty = qty cho TẤT CẢ items, bỏ short
  const markAllPicked = async (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const now = new Date().toISOString()
    const newItems = (ord.items || []).map((it: any) => ({
      ...it,
      picked_qty: it.qty,
      short_qty: 0,
      short_note: '',
      picked_at: now,
    }))
    const upd: any = {
      items: newItems,
      picking_started_at: ord.picking_started_at || now,
      updated_at: now,
    }
    // Ghi nhận NV đầu tiên tác động vào đơn là người nhặt
    if (!ord.assigned_to) upd.assigned_to = user.id
    await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
  }

  const reportShort = async (orderCode: string, itemCode: string, shortQty: number, note: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const newItems = (ord.items || []).map((it: any) => {
      if (it.code === itemCode) return { ...it, short_qty: shortQty, short_note: note }
      return it
    })
    await db.from('packing_workflow').update({ items: newItems, updated_at: new Date().toISOString() })
      .eq('order_code', orderCode)
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, items: newItems} : o))
    const item = (ord.items||[]).find((it: any) => it.code === itemCode)
    if (item && shortQty > 0) {
      await db.from('shortage_items').insert({
        id: `sh_pick_${orderCode}_${itemCode}_${Date.now()}`,
        product_code: itemCode, product_name: item.name,
        qty_short: shortQty, unit: item.unit || '',
        reported_by: user.id, status: 'pending',
        note: `Từ đơn nhặt ${orderCode}. ${note||''}`.trim(),
        created_at: new Date().toISOString(),
      })
    }
  }

  const finishPicking = async (orderCode: string) => {
    const ord = orders.find((o: any) => o.order_code === orderCode)
    if (!ord) return
    const allPicked = (ord.items||[]).every((it: any) => (it.picked_qty||0) + (it.short_qty||0) >= it.qty)
    if (!allPicked) {
      if (!(await confirmDialog({ title: 'Còn SP chưa nhặt đủ. Xác nhận hoàn tất nhặt?' }))) return
    }
    const upd: any = {
      status: 'packing',
      picked_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
    }
    // Đảm bảo có người nhặt được ghi nhận
    if (!ord.assigned_to) upd.assigned_to = user.id
    const { error } = await db.from('packing_workflow').update(upd).eq('order_code', orderCode)
    if (error) { toast.error('Lỗi: ' + error.message); return }
    setOrders(prev => prev.map((o: any) => o.order_code === orderCode ? {...o, ...upd} : o))
    setSelectedCode(null)
    toast.success('Đã hoàn tất nhặt, đơn chuyển sang bước Đóng hàng')
  }

  if (loading) return <div style={{ padding:p }}><SkeletonList rows={5} mobile={mobile}/></div>

  const selected = selectedCode ? orders.find((o: any) => o.order_code === selectedCode) : null

  // Desktop layout: 2 cột (list + detail)
  // Mobile: stack (chỉ thấy 1 cái tại 1 lần)
  const showDetail = selected !== null
  const showList = !mobile || !showDetail

  return (
    <PageContainer mobile={mobile}>
      <Topbar mobile={mobile} title="📥 Nhặt hàng"
        subtitle={`${todoOrders.length} đơn chờ nhặt • ${doneTodayOrders.length} đã xong hôm nay`}
        action={
          <div style={{ display:'flex', gap:8, alignItems:'center' }}>
            <KVSyncBadge serverSyncAt={serverSyncAt} fetching={syncing} paused={!!selectedCode}/>
            <button onClick={syncKV} disabled={syncing} title="Gọi KiotViet ngay lập tức (bypass cron 30s)"
              style={{ padding:'6px 14px', borderRadius:20, border:`1px solid ${T.gold}`,
                background: syncing ? T.border : T.goldBg, color:T.goldText, cursor: syncing ? 'wait' : 'pointer',
                fontFamily:'inherit', fontSize:11, fontWeight:700 }}>
              {syncing ? '⏳ Đang sync...' : '🔄 Sync ngay'}
            </button>
          </div>
        }/>

      {/* Cutoff banner — Giai đoạn chuyển giao */}
      {cutoffDate ? (
        <Card style={{ padding:10, marginBottom:10, background:T.goldBg,
          border:`1px solid ${T.gold}` }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:10, flexWrap:'wrap' }}>
            <div style={{ fontSize:11, color:T.goldText }}>
              🚦 Chỉ theo dõi đơn từ <b>{cutoffDate.split('-').reverse().join('/')}</b> trở đi.
              Đơn cũ xử lý theo quy trình cũ được bỏ qua.
            </div>
            {isAdmin && (
              <button onClick={() => setShowCutoffModal(true)}
                style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.gold}`,
                  background:'#fff', color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                  fontSize:10, fontWeight:600, whiteSpace:'nowrap' }}>
                🔧 Đổi ngày
              </button>
            )}
          </div>
        </Card>
      ) : (
        isAdmin && (
          <Card style={{ padding:10, marginBottom:10, background:T.bg, border:`1px dashed ${T.border}` }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:10, flexWrap:'wrap' }}>
              <div style={{ fontSize:11, color:T.light }}>
                ℹ️ Chưa set ngày bắt đầu — tất cả đơn có "Đã đóng" đều được sync
              </div>
              <button onClick={() => setShowCutoffModal(true)}
                style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.gold}`,
                  background:T.goldBg, color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                  fontSize:10, fontWeight:600, whiteSpace:'nowrap' }}>
                🚦 Set ngày bắt đầu
              </button>
            </div>
          </Card>
        )
      )}

      {/* Tabs */}
      <div style={{ display:'flex', gap:6, marginBottom:14, flexWrap:'wrap' }}>
        {[
          { id:'todo',       label:`📥 Chờ nhặt${todoOrders.length?` (${todoOrders.length})`:''}` },
          { id:'done_today', label:`✅ Xong hôm nay${doneTodayOrders.length?` (${doneTodayOrders.length})`:''}` },
        ].map((t: any) => (
          <button key={t.id} onClick={() => { setTab(t.id as any); setSelectedCode(null) }}
            style={{ padding:'6px 14px', borderRadius:20, cursor:'pointer', fontFamily:'inherit', fontSize:12,
              border:`1.5px solid ${tab===t.id?T.gold:T.border}`,
              background:tab===t.id?T.goldBg:'transparent',
              color:tab===t.id?T.goldText:T.med, fontWeight:tab===t.id?700:400 }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* 2-column layout (desktop) / stacked (mobile) */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: mobile ? '1fr' : (showDetail ? '380px 1fr' : '1fr'),
        gap: 14,
        alignItems: 'flex-start',
      }}>
        {/* ─── Column 1: List ─── */}
        {showList && (
          <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
            {/* Search */}
            <Card style={{ padding:10 }}>
              <input value={searchQ} onChange={e => setSearchQ(e.target.value)}
                placeholder="🔍 Tìm mã đơn, khách, sale..."
                style={{ width:'100%', padding:'7px 11px', border:`1px solid ${T.border}`, borderRadius:8,
                  fontSize:12, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
                  boxSizing:'border-box' as any }}/>
            </Card>

            {/* List orders */}
            {displayOrders.length === 0 ? (
              <div style={{ padding:'40px 20px', textAlign:'center', color:T.light, fontSize:13 }}>
                {tab==='todo' ? '🎉 Không còn đơn chờ nhặt!' : 'Chưa có đơn nào xong hôm nay.'}
              </div>
            ) : (
              displayOrders.map((o: any) => {
                const totalItems  = (o.items||[]).length
                const pickedItems = (o.items||[]).filter((it: any) => (it.picked_qty||0) + (it.short_qty||0) >= it.qty).length
                const short = (o.items||[]).filter((it: any) => (it.short_qty||0) > 0).length
                const isSelected = o.order_code === selectedCode
                const daysOld = Math.floor((Date.now() - new Date(o.purchase_date).getTime())/86400000)
                const pickerName = o.assigned_to
                  ? (allUsers.find((u: any) => u.id === o.assigned_to)?.name || '?')
                  : null
                const pickedTime = o.picked_at
                  ? new Date(o.picked_at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                  : null
                const packedTime = o.packed_at
                  ? new Date(o.packed_at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                  : null
                const detectedTime = o.detected_at
                  ? new Date(o.detected_at).toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})
                  : null
                const detectedDate = o.detected_at
                  ? new Date(o.detected_at).toLocaleDateString('vi-VN', {day:'2-digit', month:'2-digit'})
                  : null
                const isDetectedToday = o.detected_at &&
                  new Date(o.detected_at).toDateString() === new Date().toDateString()
                // Đơn đã đóng xong hay chưa
                const fullyPacked = o.status === 'done' && !!o.packed_at
                return (
                  <Card key={o.order_code}
                    onClick={() => setSelectedCode(o.order_code)}
                    style={{ padding:10, cursor:'pointer',
                      borderLeft: isSelected ? `4px solid ${T.gold}` : `4px solid transparent`,
                      background: isSelected ? T.goldBg : '#fff',
                      transition:'all .15s' }}>
                    <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', gap:6 }}>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:12, fontWeight:700, color:T.dark,
                          whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
                          {o.order_code} • {o.customer_name || 'KH lẻ'}
                          {Number(o.total_amount)>0 && (
                            <span style={{ color:T.goldText, fontWeight:700, marginLeft:6 }}>
                              • {Number(o.total_amount).toLocaleString('vi-VN')}đ
                            </span>
                          )}
                        </div>
                        <div style={{ fontSize:10, color:T.light, marginTop:2 }}>
                          Sale: {o.sold_by_name||'—'} • {daysOld>0?`${daysOld}N trước`:'hôm nay'}
                          {o.printed_by_name && <> • 🖨 {o.printed_by_name}</>}
                        </div>
                        {/* Tab "Chờ nhặt" hiện thời điểm đơn được sync từ KV (có ghi chú "đã đóng") */}
                        {tab === 'todo' && detectedTime && (
                          <div style={{ fontSize:10, color:T.amber, marginTop:3, fontWeight:600 }}>
                            📥 Vào kho: {isDetectedToday ? detectedTime : `${detectedDate} ${detectedTime}`}
                          </div>
                        )}
                        {/* Tab "Xong hôm nay" hiện timeline đầy đủ: Nhặt + Đã đóng */}
                        {tab === 'done_today' && (
                          <>
                            {pickerName && (
                              <div style={{ fontSize:10, color:T.green, marginTop:3, fontWeight:600 }}>
                                👤 Nhặt: {pickerName}
                                {pickedTime && <span style={{ color:T.light, fontWeight:400 }}> • {pickedTime}</span>}
                              </div>
                            )}
                            {fullyPacked ? (
                              <div style={{ fontSize:10, color:T.blue, marginTop:2, fontWeight:600 }}>
                                📮 Đã đóng xong
                                {packedTime && <span style={{ color:T.light, fontWeight:400 }}> • {packedTime}</span>}
                              </div>
                            ) : (
                              <div style={{ fontSize:10, color:T.amber, marginTop:2, fontWeight:600 }}>
                                ⏳ Đang chờ đóng gói
                              </div>
                            )}
                          </>
                        )}
                      </div>
                      <div style={{ textAlign:'right', fontSize:10, color:T.med, flexShrink:0 }}>
                        <div style={{ fontWeight:700, color: pickedItems===totalItems?T.green:T.dark }}>
                          {pickedItems}/{totalItems}
                        </div>
                        {short>0 && <div style={{ color:T.red, fontSize:9 }}>⚠️{short}</div>}
                      </div>
                    </div>
                  </Card>
                )
              })
            )}
          </div>
        )}

        {/* ─── Column 2: Detail ─── */}
        {showDetail && selected && (
          <PickingDetailPanel
            ord={selected}
            mobile={mobile}
            productMap={productMap}
            totalOrderedByCode={totalOrderedByCode}
            onClose={() => setSelectedCode(null)}
            onUpdateQty={(code: string, qty: number) => updatePickedQty(selected.order_code, code, qty)}
            onReportShort={(code: string, qty: number, note: string) => reportShort(selected.order_code, code, qty, note)}
            onMarkAllPicked={() => markAllPicked(selected.order_code)}
            onFinish={() => finishPicking(selected.order_code)}
            canPick={canPick && selected.status === 'picking'}
          />
        )}
      </div>

      {showCutoffModal && isAdmin && (
        <CutoffDateModal
          user={user}
          currentDate={cutoffDate}
          orderCount={orders.filter((o: any) =>
            (o.status === 'picking' || o.status === 'packing') &&
            (!cutoffDate || new Date(o.purchase_date) < new Date((cutoffDate||'') + 'T00:00:00'))
          ).length}
          onSave={async (newDate: string|null) => {
            const { error } = await db.from('settings').update({
              picking_start_date: newDate,
              picking_start_note: newDate ? `Set bởi ${user.name || user.ini} lúc ${new Date().toLocaleString('vi-VN')}` : '',
            }).eq('id', 'main')
            if (error) { toast.error('Lỗi: ' + error.message); return }
            setCutoffDate(newDate)
            setShowCutoffModal(false)
            alert(newDate
              ? `✅ Đã set ngày bắt đầu = ${newDate.split('-').reverse().join('/')}\nLần sync tiếp theo sẽ bỏ qua đơn trước ngày này.`
              : '✅ Đã xoá ngày bắt đầu. Tất cả đơn "Đã đóng" sẽ được sync.'
            )
          }}
          onCleanupOld={async () => {
            if (!cutoffDate) return
            const cutoffTime = new Date(cutoffDate + 'T00:00:00').getTime()
            // Safeguard: CHỈ xoá đơn picking/packing có cả purchase_date VÀ updated_at trước cutoff
            // Điều này bảo vệ đơn cũ nhưng đang được Kho xử lý (updated_at mới)
            const toDelete = orders.filter((o: any) => {
              if (o.status !== 'picking' && o.status !== 'packing') return false
              // Phải có purchase_date cũ
              if (!o.purchase_date || new Date(o.purchase_date).getTime() >= cutoffTime) return false
              // Phải KHÔNG được update gần đây (tránh xoá đơn đang xử lý)
              const lastUpd = o.updated_at || o.created_at
              if (lastUpd && new Date(lastUpd).getTime() >= cutoffTime) return false
              // Phải KHÔNG có ảnh đã chụp (NV đã bắt đầu công việc)
              if ((o.photos_picked||[]).length > 0) return false
              if ((o.photos_packed||[]).length > 0) return false
              // Phải KHÔNG có item đã picked
              const hasPickedItems = (o.items||[]).some((it: any) =>
                (Number(it.picked_qty)||0) > 0 || (Number(it.short_qty)||0) > 0
              )
              if (hasPickedItems) return false
              return true
            })
            if (toDelete.length === 0) {
              toast.success('Không có đơn nào cần dọn dẹp.\n\nLưu ý: đơn nào đang được Kho xử lý (đã có ảnh/items đã nhặt/updated gần đây) sẽ được BẢO VỆ không xoá, dù purchase_date cũ.')
              return
            }
            if (!(await confirmDialog({
              title: `Xoá ${toDelete.length} đơn cũ?`,
              message: `Trước ngày ${cutoffDate.split('-').reverse().join('/')} · trạng thái picking/packing.\n\n⚠️ Đã loại trừ các đơn đang xử lý (có ảnh, có items đã nhặt, hoặc updated gần đây).\n\nHành động này không thể hoàn tác.`,
              confirmText: 'Xoá',
              tone: 'danger',
            }))) return
            const codes = toDelete.map(o => o.order_code)
            for (const code of codes) {
              await logAudit({
                user, action: 'delete', table: 'packing_workflow', recordId: code,
                snapshot: toDelete.find(o => o.order_code === code),
                note: `Dọn dẹp đơn cũ (trước cutoff ${cutoffDate})`,
              })
            }
            await db.from('packing_workflow').delete().in('order_code', codes)
            setOrders(prev => prev.filter(o => !codes.includes(o.order_code)))
            toast.success(`Đã xoá ${codes.length} đơn cũ. Đã ghi vào audit log.`)
          }}
          onClose={() => setShowCutoffModal(false)}
        />
      )}
    </PageContainer>
  )
}

// ── Modal set cutoff date ──
function CutoffDateModal({ user, currentDate, orderCount, onSave, onCleanupOld, onClose }: any) {
  const [date, setDate] = useState<string>(currentDate || new Date().toISOString().split('T')[0])
  const [mode, setMode] = useState<'keep'|'clear'>(currentDate ? 'keep' : 'keep')

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.55)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, maxWidth:520, width:'100%',
        maxHeight:'90vh', overflow:'auto' }}>
        <div style={{ padding:'14px 20px', background:T.goldBg, borderBottom:`1px solid ${T.gold}` }}>
          <div style={{ fontSize:14, fontWeight:700, color:T.goldText }}>
            🚦 Ngày bắt đầu sync đơn
          </div>
          <div style={{ fontSize:11, color:T.med, marginTop:3 }}>
            Giai đoạn chuyển giao: bỏ qua đơn cũ đã xử lý theo quy trình cũ
          </div>
        </div>

        <div style={{ padding:20 }}>
          <div style={{ fontSize:12, color:T.dark, lineHeight:1.6, marginBottom:14 }}>
            Chọn ngày bắt đầu theo dõi. Hệ thống sẽ <b>chỉ sync đơn có ngày tạo (purchase_date) từ ngày này trở đi</b>. Đơn cũ hơn sẽ bị bỏ qua.
          </div>

          <label style={{ fontSize:11, color:T.med, fontWeight:600, display:'block', marginBottom:4 }}>
            Ngày bắt đầu
          </label>
          <input type="date" value={date} onChange={e => setDate(e.target.value)}
            max={new Date().toISOString().split('T')[0]}
            style={{ width:'100%', padding:'10px 13px', border:`1px solid ${T.border}`, borderRadius:6,
              fontSize:14, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
              boxSizing:'border-box' as any, marginBottom:14  }}/>

          <div style={{ display:'flex', gap:6, marginBottom:14, flexWrap:'wrap' }}>
            <button onClick={() => setDate(new Date().toISOString().split('T')[0])}
              style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                fontSize:10, fontWeight:600 }}>
              Hôm nay
            </button>
            <button onClick={() => {
              const d = new Date(); d.setDate(d.getDate() + 1)
              setDate(d.toISOString().split('T')[0])
            }}
              style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                fontSize:10, fontWeight:600 }}>
              Mai
            </button>
            <button onClick={() => {
              const d = new Date(); d.setDate(d.getDate() + 7 - d.getDay())
              setDate(d.toISOString().split('T')[0])
            }}
              style={{ padding:'4px 10px', borderRadius:12, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit',
                fontSize:10, fontWeight:600 }}>
              CN tuần này
            </button>
          </div>

          {currentDate && orderCount > 0 && (
            <Card style={{ padding:12, marginBottom:14, background:T.amberBg,
              border:`1px solid ${T.amber}` }}>
              <div style={{ fontSize:11, color:T.amber, fontWeight:700, marginBottom:4 }}>
                ⚠️ Có <b>{orderCount}</b> đơn cũ (trước {currentDate.split('-').reverse().join('/')}) vẫn đang ở trạng thái picking/packing
              </div>
              <div style={{ fontSize:10, color:T.dark, marginBottom:8, lineHeight:1.5 }}>
                Các đơn này đã được lọc khỏi list nhưng vẫn còn trong database. Có thể xoá hẳn để dọn dẹp.
              </div>
              <button onClick={onCleanupOld}
                style={{ padding:'5px 12px', borderRadius:6, border:`1px solid ${T.red}`,
                  background:'#fff', color:T.red, cursor:'pointer', fontFamily:'inherit',
                  fontSize:11, fontWeight:700 }}>
                🗑️ Xoá {orderCount} đơn cũ
              </button>
            </Card>
          )}

          <div style={{ padding:10, background:T.bg, borderRadius:6, fontSize:10,
            color:T.med, lineHeight:1.5 }}>
            💡 <b>Gợi ý chọn ngày:</b>
            <br/>• Ngày đầu tiên anh dùng quy trình mới (VD: hôm nay nếu go-live ngay)
            <br/>• Hoặc ngày thông báo chính thức cho NV Kho dùng app
            <br/>• Sale cũng nên được thông báo: "Từ ngày X, chỉ đơn mới mới vào hệ thống chụp ảnh"
          </div>
        </div>

        <div style={{ display:'flex', gap:10, padding:16, borderTop:`1px solid ${T.border}` }}>
          <button onClick={onClose}
            style={{ flex:1, padding:'9px', borderRadius:6, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
            Hủy
          </button>
          {currentDate && (
            <button onClick={async () => {
              if (!(await confirmDialog({ title: 'Xoá ngày bắt đầu?', message: 'Tất cả đơn "Đã đóng" sẽ được sync lại.', confirmText: 'Xoá', tone: 'warning' }))) return
              onSave(null)
            }}
              style={{ padding:'9px 12px', borderRadius:6, border:`1px solid ${T.border}`,
                background:'#fff', color:T.red, cursor:'pointer', fontFamily:'inherit',
                fontSize:11, fontWeight:600 }}>
              🗑️ Xoá set
            </button>
          )}
          <button onClick={() => onSave(date)}
            disabled={!date}
            style={{ flex:2, padding:'9px', borderRadius:6, border:'none',
              background: date ? T.gold : T.border,
              color: date ? '#fff' : T.light,
              cursor: date ? 'pointer' : 'not-allowed',
              fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
            💾 Lưu ngày bắt đầu
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Picking Detail Panel (cột phải) ──
function PickingDetailPanel({ ord, mobile, productMap, totalOrderedByCode, onClose, onUpdateQty, onReportShort, onMarkAllPicked, onFinish, canPick }: any) {
  const [searchSP, setSearchSP] = useState('')
  const [showShortModal, setShowShortModal] = useState<any>(null)
  const [showImgModal, setShowImgModal] = useState<string|null>(null)

  const norm = (s: string) => (s||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').trim()
  const items = ord.items || []
  const filtered = items.filter((it: any) => {
    if (!searchSP.trim()) return true
    return norm(`${it.code} ${it.name}`).includes(norm(searchSP))
  })

  const totalQty   = items.reduce((s: number, it: any) => s + it.qty, 0)
  const pickedQty  = items.reduce((s: number, it: any) => s + (it.picked_qty||0) + (it.short_qty||0), 0)
  const progress   = totalQty > 0 ? Math.round(pickedQty*100/totalQty) : 0
  const pickedItems = items.filter((it: any) => (it.picked_qty||0) + (it.short_qty||0) >= it.qty).length

  const getStock = (code: string, fallback: number) => {
    const p = productMap?.get(code)
    if (p && p.stock !== null && p.stock !== undefined) return p.stock
    return fallback || 0
  }
  const getTotalOrdered = (code: string) => totalOrderedByCode?.get(code) || { totalQty: 0, orderCount: 0 }

  return (
    <div style={{ background:T.card, borderRadius:12, border:`1px solid ${T.border}`,
      padding:16, position: mobile ? 'static' : 'sticky', top: 0, maxHeight: mobile ? 'none' : 'calc(100vh - 40px)',
      overflowY: 'auto', boxShadow:'0 2px 8px rgba(0,0,0,0.04)' }}>

      {/* Header */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between',
        paddingBottom:12, borderBottom:`1px solid ${T.border}`, marginBottom:12 }}>
        <div>
          <div style={{ fontSize:14, fontWeight:700, color:T.dark }}>
            {ord.order_code} • {ord.customer_name}
            {Number(ord.total_amount)>0 && (
              <span style={{ color:T.goldText, fontWeight:700, marginLeft:6 }}>
                • {Number(ord.total_amount).toLocaleString('vi-VN')}đ
              </span>
            )}
          </div>
          <div style={{ fontSize:11, color:T.light, marginTop:2 }}>
            Sale: {ord.sold_by_name||'—'}
            {ord.printed_by_name && <> • 🖨 Người in: <b style={{ color:T.dark }}>{ord.printed_by_name}</b></>}
          </div>
        </div>
        <button onClick={onClose}
          style={{ padding:'5px 10px', borderRadius:6, border:`1px solid ${T.border}`,
            background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:11 }}>
          ✕ Đóng
        </button>
      </div>

      {ord.description_kv && (
        <div style={{ padding:'8px 12px', marginBottom:12, background:T.goldBg,
          border:`1px solid ${T.goldBorder}`, borderRadius:6 }}>
          <div style={{ fontSize:10, color:T.goldText, fontWeight:600 }}>📝 Ghi chú KV:</div>
          <div style={{ fontSize:11, color:T.dark, marginTop:3 }}>{ord.description_kv}</div>
        </div>
      )}

      {ord.status !== 'picking' && (
        <div style={{ padding:'8px 12px', marginBottom:12, background:T.greenBg,
          borderRadius:6, fontSize:11, color:T.green, fontWeight:600 }}>
          ✓ Đơn này đã hoàn tất nhặt
          {ord.picked_at && <> lúc {new Date(ord.picked_at).toLocaleString('vi-VN',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'2-digit'})}</>}
        </div>
      )}

      {/* Progress */}
      <div style={{ marginBottom:12 }}>
        <div style={{ display:'flex', justifyContent:'space-between', marginBottom:6, fontSize:11, color:T.med }}>
          <span>Tiến độ: <b style={{ color:T.dark }}>{pickedItems}/{items.length}</b> SP đủ</span>
          <span>{progress}%</span>
        </div>
        <div style={{ height:8, background:T.border, borderRadius:4 }}>
          <div style={{ height:'100%', borderRadius:4,
            background: progress===100 ? T.green : T.gold,
            width:`${progress}%`, transition:'width .3s' }}/>
        </div>
      </div>

      <input value={searchSP} onChange={e => setSearchSP(e.target.value)}
        placeholder="🔍 Tìm SP trong đơn..."
        style={{ width:'100%', padding:'6px 10px', border:`1px solid ${T.border}`, borderRadius:6,
          fontSize:11, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
          boxSizing:'border-box' as any, marginBottom:10 }}/>

      {/* Items — Số lượng ĐƠN NÀY = TO, tồn + tổng đặt = nhỏ bên */}
      <div style={{ display:'flex', flexDirection:'column', gap:8, marginBottom:12 }}>
        {filtered.map((it: any) => {
          const done = (it.picked_qty||0) + (it.short_qty||0) >= it.qty
          const hasShort = (it.short_qty||0) > 0
          const realStock = getStock(it.code, it.stock)
          // KH đặt thật từ KV (products.ordered_qty) — match với "Khách đặt" trên KiotViet
          const prodInfo = productMap?.get(it.code)
          const kvOrderedQty = Number(prodInfo?.ordered_qty ?? prodInfo?.reserved ?? 0)
          // Số đơn ĐANG chờ nhặt trong app cùng đặt SP này (context phụ)
          const { orderCount } = getTotalOrdered(it.code)
          const stockShort = realStock < kvOrderedQty  // tồn < tổng KH đặt KV → cảnh báo
          const multiOrders = orderCount > 1
          return (
            <div key={it.code} style={{ padding:12, borderRadius:10,
              background: done ? (hasShort ? T.redBg : T.greenBg) : '#fff',
              border: `1px solid ${done ? (hasShort?T.red:T.green) : T.border}`,
              borderLeft: `4px solid ${done ? (hasShort?T.red:T.green) : (stockShort?T.amber:T.border)}` }}>

              {/* Row 1: Tên + Nút ảnh */}
              <div style={{ display:'flex', alignItems:'flex-start', gap:8, marginBottom:8 }}>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:13, fontWeight:700, color:T.dark, lineHeight:1.35 }}>
                    {it.name}
                  </div>
                  <div style={{ fontSize:10, color:T.light, marginTop:2, display:'flex', gap:8, flexWrap:'wrap' }}>
                    <span>{it.code}</span>
                    {it.unit && <span>{it.unit}</span>}
                    <span>• 📦 Tồn: <b style={{ color: stockShort ? T.amber : T.dark }}>{realStock}</b></span>
                    <span>• 🛒 KH đặt (KV): <b style={{ color: stockShort ? T.amber : T.blue }}>{kvOrderedQty.toLocaleString('vi-VN')}</b></span>
                    {multiOrders && (
                      <span style={{ color: T.blue, fontWeight:600 }}>
                        • 📋 {orderCount} đơn chờ nhặt
                      </span>
                    )}
                    {stockShort && <span style={{ color:T.amber, fontWeight:700 }}>⚠️ KHẢ NĂNG THIẾU</span>}
                  </div>
                </div>
                <button onClick={() => setShowImgModal(it.code)}
                  style={{ padding:'6px 10px', borderRadius:6, border:`1px solid ${T.gold}`,
                    background:T.goldBg, color:T.goldText, cursor:'pointer', fontFamily:'inherit',
                    fontSize:11, fontWeight:600, flexShrink:0, whiteSpace:'nowrap' }}>
                  🖼 Ảnh SP
                </button>
              </div>

              {/* Row 2: SỐ LƯỢNG ĐƠN NÀY — TO HOÀNH TRÁNG */}
              <div style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 14px',
                background: done ? 'transparent' : T.bg, borderRadius:8,
                border: done ? 'none' : `1px solid ${T.border}`, marginBottom:10 }}>
                <div style={{ flex:1, textAlign:'center' }}>
                  <div style={{ fontSize:10, color:T.light, fontWeight:700, letterSpacing:1, marginBottom:2 }}>
                    SỐ LƯỢNG CẦN NHẶT
                  </div>
                  <div style={{ fontSize:42, fontWeight:900, color: done ? T.green : T.dark,
                    lineHeight:1, letterSpacing:-1 }}>
                    {it.qty}
                  </div>
                </div>
                {canPick && (
                  <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
                    <div style={{ display:'flex', alignItems:'center', gap:6 }}>
                      <button onClick={() => onUpdateQty(it.code, Math.max(0, (it.picked_qty||0)-1))}
                        disabled={(it.picked_qty||0)<=0}
                        style={{ width:42, height:42, borderRadius:8, border:`2px solid ${T.border}`,
                          background:'#fff', cursor:'pointer', fontSize:22, fontWeight:700, fontFamily:'inherit',
                          color:(it.picked_qty||0)<=0?T.light:T.dark, padding:0 }}>−</button>
                      <div style={{ minWidth:60, textAlign:'center' }}>
                        <div style={{ fontSize:9, color:T.light, fontWeight:600 }}>ĐÃ NHẶT</div>
                        <div style={{ fontSize:24, fontWeight:800, color: done?T.green:T.dark, lineHeight:1 }}>
                          {it.picked_qty||0}
                        </div>
                      </div>
                      <button onClick={() => onUpdateQty(it.code, (it.picked_qty||0)+1)}
                        disabled={(it.picked_qty||0)>=it.qty}
                        style={{ width:42, height:42, borderRadius:8, border:`2px solid ${T.border}`,
                          background:'#fff', cursor:'pointer', fontSize:22, fontWeight:700, fontFamily:'inherit',
                          color:(it.picked_qty||0)>=it.qty?T.light:T.dark, padding:0 }}>+</button>
                    </div>
                  </div>
                )}
              </div>

              {/* Row 3: nút thao tác nhanh */}
              {canPick && (
                <div style={{ display:'flex', gap:8 }}>
                  <button onClick={() => onUpdateQty(it.code, it.qty)}
                    style={{ flex:1, padding:'10px', borderRadius:6,
                      border:`1.5px solid ${T.green}`,
                      background: done && !hasShort ? T.green : '#fff',
                      color: done && !hasShort ? '#fff' : T.green,
                      cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
                    ✓ Đủ hàng
                  </button>
                  <button onClick={() => setShowShortModal(it)}
                    style={{ flex:1, padding:'10px', borderRadius:6,
                      border:`1.5px solid ${T.red}`,
                      background: hasShort ? T.red : '#fff',
                      color: hasShort ? '#fff' : T.red,
                      cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
                    ⚠️ Báo thiếu
                  </button>
                </div>
              )}

              {hasShort && (
                <div style={{ fontSize:11, color:T.red, marginTop:8, padding:'6px 10px',
                  background:'#fff', borderRadius:6, border:`1px solid ${T.red}` }}>
                  ⚠️ Thiếu <b>{it.short_qty}</b>{it.short_note?`: ${it.short_note}`:''}
                </div>
              )}
            </div>
          )
        })}
      </div>

      {/* Footer */}
      {canPick && (
        <>
          {/* Nút nhặt đủ toàn bộ */}
          <div style={{ marginBottom:10 }}>
            <button onClick={() => {
              if (confirm(`Bạn xác nhận đã nhặt đủ đơn ${ord.order_code}?\n\nThao tác này sẽ đánh dấu TẤT CẢ sản phẩm là đã nhặt đủ số lượng yêu cầu.`)) {
                onMarkAllPicked()
              }
            }}
              style={{ width:'100%', padding:'10px', borderRadius:8, border:`2px dashed ${T.green}`,
                background:T.greenBg, color:T.green, cursor:'pointer', fontFamily:'inherit',
                fontSize:12, fontWeight:700 }}>
              ✅ Nhặt đủ toàn bộ
            </button>
          </div>
          <div style={{ display:'flex', gap:8, paddingTop:10, borderTop:`1px solid ${T.border}` }}>
            <button onClick={onClose}
              style={{ flex:1, padding:'10px', borderRadius:6, border:`1px solid ${T.border}`,
                background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>
              ⏸ Tạm
            </button>
            <button onClick={onFinish}
              style={{ flex:2, padding:'10px', borderRadius:6, border:'none',
                background:`linear-gradient(135deg, ${T.green} 0%, #107035 100%)`, color:'#fff',
                cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:700 }}>
              ✓ Hoàn tất nhặt
            </button>
          </div>
        </>
      )}

      {showShortModal && (
        <ShortageModalV2 item={showShortModal} onClose={() => setShowShortModal(null)}
          onSubmit={(qty: number, note: string) => {
            onReportShort(showShortModal.code, qty, note)
            setShowShortModal(null)
          }}/>
      )}
      {showImgModal && (
        <ProductImageModalV2 code={showImgModal} onClose={() => setShowImgModal(null)}/>
      )}
    </div>
  )
}

function ShortageModalV2({ item, onClose, onSubmit }: any) {
  const [qty, setQty]   = useState(String(item.short_qty || (item.qty - (item.picked_qty||0))))
  const [note, setNote] = useState(item.short_note || '')
  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ background:'#fff', borderRadius:12, padding:20, maxWidth:420, width:'100%' }}>
        <div style={{ fontSize:15, fontWeight:700, color:T.dark, marginBottom:6 }}>⚠️ Báo thiếu hàng</div>
        <div style={{ fontSize:12, color:T.med, marginBottom:14 }}>{item.name} ({item.code})</div>
        <label style={{ fontSize:11, color:T.med, fontWeight:600, display:'block', marginBottom:4 }}>
          Số lượng thiếu (còn {item.qty} cần nhặt)
        </label>
        <input type="number" value={qty} onChange={e => setQty(e.target.value)} min="0" max={item.qty}
          style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:6,
            fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
            boxSizing:'border-box' as any, marginBottom:12 }}/>
        <label style={{ fontSize:11, color:T.med, fontWeight:600, display:'block', marginBottom:4 }}>
          Ghi chú (VD: Hết hàng, Vỡ hỏng...)
        </label>
        <input value={note} onChange={e => setNote(e.target.value)}
          style={{ width:'100%', padding:'8px 11px', border:`1px solid ${T.border}`, borderRadius:6,
            fontSize:13, fontFamily:'inherit', color:T.dark, background:'#fff', outline:'none',
            boxSizing:'border-box' as any, marginBottom:16 }}/>
        <div style={{ display:'flex', gap:10 }}>
          <button onClick={onClose}
            style={{ flex:1, padding:'8px', borderRadius:6, border:`1px solid ${T.border}`,
              background:'#fff', color:T.med, cursor:'pointer', fontFamily:'inherit', fontSize:12 }}>
            Hủy
          </button>
          <button onClick={() => onSubmit(Number(qty)||0, note)}
            style={{ flex:1, padding:'8px', borderRadius:6, border:'none',
              background:T.red, color:'#fff', cursor:'pointer', fontFamily:'inherit', fontSize:12, fontWeight:600 }}>
            📤 Báo thiếu
          </button>
        </div>
      </div>
    </div>
  )
}

function ProductImageModalV2({ code, onClose }: any) {
  const [info, setInfo]       = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError]     = useState<string|null>(null)

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(
          `${SUPABASE_URL}/functions/v1/kiotviet-product-info?code=${encodeURIComponent(code)}`,
          { headers: { 'Authorization': `Bearer ${SUPABASE_ANON}` } }
        )
        const data = await res.json()
        if (data.error) setError(data.error)
        else setInfo(data)
      } catch(e: any) {
        setError(e.message)
      }
      setLoading(false)
    })()
  }, [code])

  const imgs: string[] = info?.images || []

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.85)', zIndex:9999,
      display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}
      onClick={onClose}>
      <div style={{ background:'#fff', borderRadius:12, padding:20, maxWidth:600, width:'100%',
        maxHeight:'90vh', overflow:'auto' }} onClick={e => e.stopPropagation()}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
          <div>
            <div style={{ fontSize:14, fontWeight:700, color:T.dark }}>{info?.name || code}</div>
            <div style={{ fontSize:11, color:T.light, marginTop:3 }}>
              Mã: {code}
              {info && <> • Tồn: <b style={{ color:T.green }}>{info.stock}</b></>}
              {info?.unit && <> • {info.unit}</>}
            </div>
          </div>
          <button onClick={onClose}
            style={{ background:'transparent', border:'none', fontSize:22, cursor:'pointer',
              color:T.med, padding:'0 6px', lineHeight:1 }}>
            ×
          </button>
        </div>

        {loading && <SkeletonList rows={3}/>}

        {error && (
          <ErrorState
            title="Không tải được ảnh từ KiotViet"
            description={error}
            tone="error"
          />
        )}

        {!loading && !error && imgs.length === 0 && (
          <div style={{ padding:40, textAlign:'center', color:T.light, fontSize:13,
            background:T.bg, borderRadius:8 }}>
            📷 SP này chưa có ảnh trên KiotViet.<br/>
            <span style={{ fontSize:11 }}>Admin có thể vào KV → Hàng hoá → Thêm ảnh.</span>
          </div>
        )}

        {!loading && imgs.length > 0 && (
          <div style={{ display:'grid', gridTemplateColumns:'1fr', gap:10 }}>
            {imgs.map((url: string, i: number) => (
              <img key={i} src={url} alt={info?.name}
                style={{ width:'100%', borderRadius:8, border:`1px solid ${T.border}`,
                  display:'block' }}
                onError={(e: any) => { e.currentTarget.style.display = 'none' }}/>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

